<script>
export default {
  name: 'FormationArea',
  data() {
    return {
      score: [0, 0],
      GPpt: [0, 0],
      clearStage: [1, 1],
      performance: [[], []],
      bonus: {
        rare: [
          {
            kaho: undefined,
            sayaka: undefined,
            rurino: undefined,
            kozue: undefined,
            tsuzuri: undefined,
            megumi: undefined
          },
          {
            kaho: undefined,
            sayaka: undefined,
            rurino: undefined,
            kozue: undefined,
            tsuzuri: undefined,
            megumi: undefined
          }
        ],
        seasonFan: [
          {
            kaho: 1,
            sayaka: 1,
            rurino: 1,
            kozue: 1,
            tsuzuri: 1,
            megumi: 1
          },
          {
            kaho: 1,
            sayaka: 1,
            rurino: 1,
            kozue: 1,
            tsuzuri: 1,
            megumi: 1
          }
        ],
        release: [
          {
            kaho: 1,
            sayaka: 1,
            rurino: 1,
            kozue: 1,
            tsuzuri: 1,
            megumi: 1
          },
          {
            kaho: 1,
            sayaka: 1,
            rurino: 1,
            kozue: 1,
            tsuzuri: 1,
            megumi: 1
          }
        ]
      },
      clearRank: [1, 1.1, 1.2, 1.3],
      seasonFanLv: [0, 0.2, 0.275, 0.35, 0.425, 0.5, 0.55, 0.6, 0.65, 0.7],
      releaseLv: {
        UR: [0, 0.2, 0.3, 0.35, 0.4],
        SR: [0, 0.15, 0.25, 0.3, 0.35],
        R: [0, 0.1, 0.15, 0.2, 0.25]
      },
      rules: [
        value => !isNaN(value) || 'еҚҠи§’ж•°еӯ—гҒ§е…ҘеҠӣгҒ—гҒҰгҒҸгҒ гҒ•гҒ„'
      ],
      styleType: {
        performer: 'гғ‘гғ•гӮ©гғјгғһгғј',
        moodMaker: 'гғ гғјгғүгғЎгғјгӮ«гғј',
        cheerLeader: 'гғҒгӮўгғӘгғјгғҖгғј',
        trickStar: 'гғҲгғӘгғғгӮҜгӮ№гӮҝгғј'
      },
      mood: {
        happy: 'гғҸгғғгғ”гғј',
        neutral: 'гғӢгғҘгғјгғҲгғ©гғ«',
        melow: 'гғЎгғӯгӮҰ'
      },
      rarity: ['DR', 'UR', 'SR', 'R'],
      styleHeadline: {
        main: 'MAIN STYLE',
        side1: 'SIDE STYLE 1',
        side2: 'SIDE STYLE 2'
      },
      selectCardList: {
        stageA: {
          kaho: {
            main: '',
            side1: '',
            side2: ''
          },
          sayaka: {
            main: '',
            side1: '',
            side2: ''
          },
          rurino: {
            main: '',
            side1: '',
            side2: ''
          },
          kozue: {
            main: '',
            side1: '',
            side2: ''
          },
          tsuzuri: {
            main: '',
            side1: '',
            side2: ''
          },
          megumi: {
            main: '',
            side1: '',
            side2: ''
          }
        },
        stageB: {},
        stageC: {}
      },
      selectTab: 'kaho'
    }
  },
  created() {},
  mounted() {},
  computed: {
    setCard() {
      return this.updateData.selectCard;
    }
  },
  methods: {
    possessionCardLoadAction() {

    },
    changeTab(selectCharactor) {
      this.selectTab = selectCharactor;
    },
    labelCaption(a, b) {
      return a + '_' + b;
    },
    setIcon(name_en) {
      return {
        'background-image':'url(' + require(`@/assets/member_icon/icon_${name_en}.png`) + ')',
        'background-position': 'center'
      };
    },
    setValue(target, v) {
      this.bonus[target[0]][target[1]][target[2]] = v;
    },
    makeGPpt(target) {
      let releaseLv = 0;
      let seasonFanLv = 0;

      for (const memberName in this.bonus.seasonFan[target]) {
        seasonFanLv += this.seasonFanLv[this.bonus.seasonFan[target][memberName] - 1];

        if (this.bonus.rare[target][memberName] !== undefined) {
          releaseLv += this.releaseLv[this.bonus.rare[target][memberName]][this.bonus.release[target][memberName] - 1];
        }
      }

      this.GPpt[target] = Math.ceil(this.score[target] * this.clearRank[this.clearStage[target] - 1] * (1 + releaseLv) * (1 + seasonFanLv)).toLocaleString();
    }
  },
  watch: {
    selectCardList: {
      deep: true,
      handler(newVal, oldVal) {
        console.log(oldVal);
        console.log(newVal);
      }
    }
  }
}
</script>

